mapper.update:
update yeark set update_time = now()

        , name = #{name}


        , open = #{open}


        , high = #{high}


        , low = #{low}


        , `close` = #{close}


        , prev_close = #{prevClose}


        , percent = #{percent}


        , volume = #{volume}


        , amount = #{amount}


        , ma5 = #{ma5}


        , ma10 = #{ma10}


        , ma20 = #{ma20}


        , ma30 = #{ma30}


        , dea = #{dea}


         , dif = #{dif}


        , macd = #{macd}


        , cross_params = #{crossParams}

      where code = #{code} and day = #{day}

mapper.select:
select d.* from yeark d where
d.code = #{code} and d.day < #{fromDay}
order by d.day desc limit 1

   	select y.code, y.day, y.open, y.`close`, y.prev_close, y.high, y.low, y.ma5, y.ma10, y.ma20, y.ma30, y.dif, y.dea, y.macd from yeark y


		  		and y.code = #{code}



				and (select count(*) from yeark where code=y.code and day > y.day) < #{nyears}
